import os
from typing import Optional
import requests
from ..utils.http import create_session
from ..utils.utils import read_token_from_file


class ControlPlaneClient:
    def __init__(
        self,
        workload_manager_url: Optional[str] = None,
        auth_token: Optional[str] = None,
        timeout: int = 120,
        connect_timeout: float = 5.0,
        pool_connections: int = 10,
        pool_maxsize: int = 10,
    ):
        self.base_url = workload_manager_url or os.getenv("WORKLOAD_MANAGER_URL")
        if not self.base_url:
            raise ValueError("workload_manager_url must be provided or WORKLOAD_MANAGER_URL must be set")

        if not self.base_url.startswith("http://") and not self.base_url.startswith("https://"):
            self.base_url = f"http://{self.base_url}"

        self.auth_token = auth_token
        if not self.auth_token:
            token_path = "/var/run/secrets/kubernetes.io/serviceaccount/token"
            self.auth_token = read_token_from_file(token_path)

        self.timeout = timeout
        self.connect_timeout = connect_timeout
        self.session = create_session(pool_connections, pool_maxsize)

        if self.auth_token:
            self.session.headers.update({
                "Authorization": f"Bearer {self.auth_token}"
            })

    def create_session(
        self,
        name: str = "my-interpreter",
        namespace: str = "default",
        metadata: Optional[dict] = None,
        ttl: int = 3600,
    ) -> str:
        url = f"{self.base_url}/v1/code-interpreter"

        payload = {
            "name": name,
            "namespace": namespace,
            "ttl": ttl,
        }

        if metadata:
            payload["metadata"] = metadata

        response = self.session.post(url, json=payload, timeout=(self.connect_timeout, self.timeout))
        response.raise_for_status()

        data = response.json()
        if "sessionId" not in data:
            raise ValueError("Response missing sessionId field")

        return data["sessionId"]

    def delete_session(self, session_id: str) -> bool:
        url = f"{self.base_url}/v1/code-interpreter/sessions/{session_id}"

        try:
            response = self.session.delete(url, timeout=(self.connect_timeout, self.timeout))
            if response.status_code == 404:
                return True
            response.raise_for_status()
            return True
        except requests.exceptions.RequestException:
            return False

    def close(self) -> None:
        self.session.close()

import os
from typing import Optional
import requests
from ..exceptions import CommandExecutionError
from ..utils.http import create_session


class CodeInterpreterDataPlaneClient:
    def __init__(
        self,
        session_id: str,
        router_url: Optional[str] = None,
        namespace: Optional[str] = None,
        cr_name: Optional[str] = None,
        base_url: Optional[str] = None,
        timeout: int = 120,
        connect_timeout: float = 5.0,
        pool_connections: int = 10,
        pool_maxsize: int = 10,
    ):
        self.session_id = session_id
        self.timeout = timeout
        self.connect_timeout = connect_timeout
        self.session = create_session(pool_connections, pool_maxsize)

        if base_url:
            self.base_url = base_url
        else:
            router_url = router_url or os.getenv("ROUTER_URL")
            if not router_url:
                raise ValueError("router_url must be provided or ROUTER_URL must be set")

            if not router_url.startswith("http://") and not router_url.startswith("https://"):
                router_url = f"http://{router_url}"

            namespace = namespace or "default"
            cr_name = cr_name or "code-interpreter"
            self.base_url = f"{router_url}/v1/namespaces/{namespace}/code-interpreters/{cr_name}/invocations"

        self.session.headers.update({
            "x-agentcube-session-id": self.session_id,
        })

    def _request(
        self,
        method: str,
        endpoint: str,
        body: Optional[dict] = None,
        **kwargs
    ) -> requests.Response:
        url = f"{self.base_url}{endpoint}"
        headers = kwargs.get("headers", {})
        headers["x-agentcube-session-id"] = self.session_id
        kwargs["headers"] = headers
        kwargs["timeout"] = kwargs.get("timeout", (self.connect_timeout, self.timeout))

        response = self.session.request(method, url, json=body, **kwargs)
        response.raise_for_status()
        return response

    def execute_command(self, command: list, timeout: Optional[int] = None) -> str:
        if not isinstance(command, list):
            command = [command]

        timeout_value = timeout or 60
        payload = {
            "command": command,
            "timeout": f"{timeout_value}s",
        }

        read_timeout = timeout_value + 2.0 if isinstance(timeout_value, (int, float)) else self.timeout

        try:
            response = self._request("POST", "/api/execute", body=payload, timeout=(self.connect_timeout, read_timeout))
            result = response.json()

            exit_code = result.get("exitCode", -1)
            if exit_code != 0:
                raise CommandExecutionError(
                    exit_code=exit_code,
                    stderr=result.get("stderr", ""),
                    command=str(command),
                )

            return result.get("stdout", "")
        except requests.exceptions.RequestException as e:
            raise CommandExecutionError(
                exit_code=-1,
                stderr=str(e),
                command=str(command),
            )

    def run_code(self, language: str, code: str, timeout: Optional[int] = None) -> str:
        language_lower = language.lower()

        if language_lower in ["python", "py", "python3"]:
            filename = "temp_script.py"
            self.write_file(code, filename)
            return self.execute_command(["python3", filename], timeout)

        raise ValueError(f"Unsupported language: {language}")

    def write_file(self, content: str, remote_path: str) -> None:
        import base64
        content_b64 = base64.b64encode(content.encode("utf-8")).decode("utf-8")

        payload = {
            "path": remote_path,
            "content": content_b64,
            "mode": "0644",
        }

        self._request("POST", "/api/files", body=payload)

    def upload_file(self, local_path: str, remote_path: str) -> None:
        with open(local_path, "rb") as f:
            files = {"file": f}
            data = {
                "path": remote_path,
                "mode": "0644",
            }
            self._request("POST", "/api/files", body=None, files=files, data=data)

    def download_file(self, remote_path: str, local_path: str) -> None:
        response = self._request("GET", f"/api/files/{remote_path}", stream=True)

        with open(local_path, "wb") as f:
            for chunk in response.iter_content(chunk_size=8192):
                f.write(chunk)

    def list_files(self, path: str = ".") -> dict:
        response = self._request("GET", f"/api/files?path={path}")
        return response.json()

    def close(self) -> None:
        self.session.close()

import os
from typing import Optional
from .clients.control_plane import ControlPlaneClient
from .clients.code_interpreter_data_plane import CodeInterpreterDataPlaneClient
from .exceptions import SessionError


class CodeInterpreterClient:
    def __init__(
        self,
        name: str = "my-interpreter",
        namespace: str = "default",
        ttl: int = 3600,
        workload_manager_url: Optional[str] = None,
        router_url: Optional[str] = None,
        auth_token: Optional[str] = None,
        verbose: bool = False,
        session_id: Optional[str] = None,
    ):
        self.name = name
        self.namespace = namespace
        self.ttl = ttl
        self.verbose = verbose
        self.session_id = session_id
        self._session_created = session_id is None

        router_url = router_url or os.getenv("ROUTER_URL")
        if not router_url:
            raise ValueError("router_url must be provided or ROUTER_URL environment variable must be set")

        self.cp_client = ControlPlaneClient(
            workload_manager_url=workload_manager_url,
            auth_token=auth_token,
        )

        if self.session_id is None:
            try:
                self.session_id = self.cp_client.create_session(
                    name=name,
                    namespace=namespace,
                    ttl=ttl,
                )
            except Exception as e:
                raise SessionError(f"Failed to create session: {e}")

        try:
            self._init_data_plane(router_url)
        except Exception as e:
            if self._session_created:
                self.cp_client.delete_session(self.session_id)
            raise SessionError(f"Failed to initialize data plane client: {e}")

    def _init_data_plane(self, router_url: str) -> None:
        self.dp_client = CodeInterpreterDataPlaneClient(
            session_id=self.session_id,
            router_url=router_url,
            namespace=self.namespace,
        )

    def __enter__(self) -> "CodeInterpreterClient":
        return self

    def __exit__(self, exc_type, exc_val, exc_tb) -> bool:
        self.stop()
        return False

    def stop(self) -> None:
        try:
            if self.dp_client:
                self.dp_client.close()
        except Exception as e:
            if self.verbose:
                print(f"Warning: Failed to close data plane client: {e}")

        try:
            if self._session_created and self.session_id:
                self.cp_client.delete_session(self.session_id)
        except Exception as e:
            if self.verbose:
                print(f"Warning: Failed to delete session: {e}")

        try:
            self.cp_client.close()
        except Exception as e:
            if self.verbose:
                print(f"Warning: Failed to close control plane client: {e}")

    def execute_command(self, command, timeout: Optional[int] = None) -> str:
        result = self.dp_client.execute_command(command, timeout)
        if self.verbose:
            print(result)
        return result

    def run_code(self, language: str, code: str, timeout: Optional[int] = None) -> str:
        result = self.dp_client.run_code(language, code, timeout)
        if self.verbose:
            print(result)
        return result

    def write_file(self, content: str, remote_path: str) -> None:
        self.dp_client.write_file(content, remote_path)
        if self.verbose:
            print(f"File written: {remote_path}")

    def upload_file(self, local_path: str, remote_path: str) -> None:
        self.dp_client.upload_file(local_path, remote_path)
        if self.verbose:
            print(f"File uploaded: {local_path} -> {remote_path}")

    def download_file(self, remote_path: str, local_path: str) -> None:
        self.dp_client.download_file(remote_path, local_path)
        if self.verbose:
            print(f"File downloaded: {remote_path} -> {local_path}")

    def list_files(self, path: str = ".") -> dict:
        result = self.dp_client.list_files(path)
        if self.verbose:
            print(f"Files in {path}: {result}")
        return result

import os
from typing import Optional, Any
from .clients.agent_runtime_data_plane import AgentRuntimeDataPlaneClient


class AgentRuntimeClient:
    def __init__(
        self,
        agent_name: str,
        namespace: str = "default",
        router_url: Optional[str] = None,
        verbose: bool = False,
        session_id: Optional[str] = None,
        timeout: int = 120,
        connect_timeout: float = 5.0,
    ):
        self.agent_name = agent_name
        self.namespace = namespace
        self.verbose = verbose
        self.timeout = timeout
        self.connect_timeout = connect_timeout

        router_url = router_url or os.getenv("ROUTER_URL")
        if not router_url:
            raise ValueError("router_url must be provided or ROUTER_URL environment variable must be set")

        self.router_url = router_url

        self.dp_client = AgentRuntimeDataPlaneClient(
            router_url=router_url,
            namespace=namespace,
            agent_name=agent_name,
            timeout=timeout,
            connect_timeout=connect_timeout,
        )

        if session_id is None:
            try:
                self.session_id = self.dp_client.bootstrap_session_id()
            except ValueError as e:
                raise ValueError(f"Failed to bootstrap session ID: {e}")
        else:
            self.session_id = session_id

        if not self.session_id:
            raise ValueError("session_id is required but could not be obtained")

    def __enter__(self) -> "AgentRuntimeClient":
        return self

    def __exit__(self, exc_type, exc_val, exc_tb) -> bool:
        self.close()
        return False

    def invoke(self, payload: Any, timeout: Optional[int] = None) -> Any:
        if not self.session_id:
            raise ValueError("session_id is required for invocation")

        response = self.dp_client.invoke(self.session_id, payload, timeout)
        result = response.json()

        if self.verbose:
            print(f"Invocation result: {result}")

        return result

    def close(self) -> None:
        try:
            self.dp_client.close()
        except Exception as e:
            if self.verbose:
                print(f"Warning: Failed to close data plane client: {e}")

